local lang = RSRG.Languages["es-es"]

-- Repartidor de misiones
lang["#MISSION_GIVER_SALTROCK"] = "Salt Rock"
lang["#MISSION_GIVER_SALTROCK_SUBTITLE"] = "Capataz Muerde Rocas"
lang["#MISSION_GIVER_SALTROCK_GREET_NEW"] = "Oye chico, puede que estés en el lugar equivocado o en el lugar correcto. Tengo algunas cosas que necesito hacer si estás interesado."
lang["#MISSION_GIVER_SALTROCK_GREET_N100"] = "Escucha, puede que hayas llamado la atención de los demás, pero yo doy oportunidades a la gente. Habla conmigo."
lang["#MISSION_GIVER_SALTROCK_GREET_0"] = "Hola, sangre nueva, no hay mucho tiempo para charlar, demuestra tu valía."
lang["#MISSION_GIVER_SALTROCK_GREET_25"] = "Subiendo de nivel, sigamos así."
lang["#MISSION_GIVER_SALTROCK_GREET_150"] = "Muy buen prospecto, muy jodidamente bueno. Eres el tema de conversación de las minas."
lang["#MISSION_GIVER_SALTROCK_GREET_FINISHED"] = "Eres un enviado del cielo, chico. Aunque me encantaría tenerte aquí, hay mucho más ahí fuera que solo esto. Vuelve a vernos, ¿de acuerdo?"

-- Misiones
lang["#MISSION_SALTROCK_BLOWTHEPATH"] = "Abriendo el Camino"
lang["#MISSION_SALTROCK_BLOWTHEPATH_DESC"] = "Escucha chico, estamos un poco ocupados ahora mismo, pero hay una oportunidad para ti. Necesitamos explosivos en bruto para reabrir un túnel colapsado y para otras necesidades, pero tenemos algo de esa mierda de energía elegante en su lugar. Consíguenos algo de dinamita, así como una de esas granadas de lata improvisadas y una granada de fragmentación adecuada también. Podemos darte algo de esa mierda de energía elegante y algo de dinero por ello, y podemos hablar más."
lang["#MISSION_SALTROCK_BLOWTHEPATH_HINT"] = "Consigue dinamita, una granada de fragmentación y una granada de lata. Puedes encontrar dinamita en la cantera bajo Salt Wells. Puedes fabricar o hacer que alguien te fabrique una granada de lata. Puedes encontrar granadas de fragmentación en cajas de explosivos o raramente en buzones."
lang["#MISSION_SALTROCK_BLOWTHEPATH_COMPLETE"] = "Bueno, ¡realmente apareciste con eso! ¡Por fin podemos abrir ese túnel! Buen trabajo chico, puede que tenga algo más para ti, aquí tienes algo de dinero y granadas verdes elegantes."

lang["#MISSION_SALTROCK_IGNOREPAST"] = "Ignorando el Pasado"
lang["#MISSION_SALTROCK_IGNOREPAST_DESC"] = "Sé quién eres. Podemos superar lo que has hecho, pero necesitamos algo de dinamita. Solo tráela y no hables mucho. Daré una buena palabra, ¿de acuerdo?"
lang["#MISSION_SALTROCK_IGNOREPAST_HINT"] = "Entrega 3 barras de Dinamita. Se pueden encontrar en varios comerciantes, en cajas de explosivos o en la cantera de Salt Wells."
lang["#MISSION_SALTROCK_IGNOREPAST_COMPLETE"] = "Se ha dado la palabra, esperemos que sea suficiente, por tu bien."

lang["#MISSION_SALTROCK_CRITTERS"] = "Pequeñas Criaturas Problemáticas"
lang["#MISSION_SALTROCK_CRITTERS_DESC"] = "Hiciste un buen trabajo consiguiéndonos esos palos explosivos, así que te diré algo, el viejo Salt Rock tiene un plan para ti. Quiero que te acostumbres a tu entorno, pero más aún, a lo que lo habita. Un montón de Hormigas merodean por esta zona, ve a hacer agujeros en un montón de ellas para mí, ¿quieres? Ah, y trata de recolectar los huevos y algo de néctar si puedes."
lang["#MISSION_SALTROCK_CRITTERS_HINT"] = "Elimina 10 Hormigas en Yolla Bolly. Se pueden encontrar en lechos de ríos y en las cuevas cerca del territorio de los Muerde Rocas. También mencionó que recogieras los huevos y el néctar por alguna razón."
lang["#MISSION_SALTROCK_CRITTERS_COMPLETE"] = "Genial, muy bien. Eliminar a algunas de ellas hace que todas se dispersen por un tiempo. Toma una máscara y algo de beber."

lang["#MISSION_SALTROCK_MININGENERGY"] = "Necesito esa Energía Minera"
lang["#MISSION_SALTROCK_MININGENERGY_DESC"] = "Oye, hice un trato con algunos de los chicos que están prospectando la cueva recién volada desde la última vez que hablamos. Necesitan algunas cosas para seguir adelante. A muchos de ellos les gusta comer huevos, algún guiso especial que hacen o algo así, pero Elliot en particular usa ese Néctar para hacer turnos largos. Dame algunos de los huevos y una bonita botella condensada de Néctar para ellos, como pensé, y puedo hacer que abran sus arcas para ti."
lang["#MISSION_SALTROCK_MININGENERGY_HINT"] = "Recoge 5 Huevos de Hormiga y 1 Néctar de Hormiga. Se pueden obtener de las Hormigas."
lang["#MISSION_SALTROCK_MININGENERGY_COMPLETE"] = "Los hiciste muy felices. Toma, elige tu parte del lote."

lang["#MISSION_SALTROCK_THEFRONTIERSMEN"] = "Los Hombres de la Frontera"
lang["#MISSION_SALTROCK_THEFRONTIERSMEN_DESC"] = "Es hora de que demuestres tu valía. Me gustas, pero los demás no confían en ti, así que esto es lo que quieren. Los que nos detienen por aquí no son la RNC, sino esos malditos supervivientes del valle. Están más centrados en quedarse con todo este lugar para ellos mismos, ¡aunque nosotros llegamos primero a Yolla! Han demostrado una y otra vez que no pueden cumplir su palabra, y ahora la RNC los está influenciando cada vez más. Elimina a algunos de ellos, 2 o 3 patrullas deberían ser suficientes."
lang["#MISSION_SALTROCK_THEFRONTIERSMEN_HINT"] = "Mata a 8 Supervivientes del Valle. Se pueden encontrar deambulando por el área de Yolla Bolly."
lang["#MISSION_SALTROCK_THEFRONTIERSMEN_COMPLETE"] = "Te estaba vigilando allí fuera. Ahora confiamos en ti, bienvenido $playername."

lang["#MISSION_SALTROCK_USEFULGECKOS"] = "Geckos Útiles"
lang["#MISSION_SALTROCK_USEFULGECKOS_DESC"] = "Oye, me alegra verte de vuelta $playername, tengo más trabajo para ti. Necesitamos una piel especial para una armadura que estamos haciendo, pero cazarlos es un problema. Tenemos algunos despellejadores habilidosos, así que esto es lo que necesito. Sal y mata un par de esos geckos dorados por aquí, y luego vuelve y dime dónde los mataste. Enviaré a mis chicos a despellejar las pieles con cuidado después, ¿te parece bien?"
lang["#MISSION_SALTROCK_USEFULGECKOS_HINT"] = "Mata a 5 Geckos Dorados en Yolla Bolly. Se pueden encontrar donde se encuentran normalmente los geckos."
lang["#MISSION_SALTROCK_USEFULGECKOS_COMPLETE"] = "Allí y allí, ¿verdad? Muy bien. Houston está en camino, aquí está tu recompensa."

lang["#MISSION_SALTROCK_BEAUTIFULSHINE"] = "Ese Hermoso Brillo Amarillo"
lang["#MISSION_SALTROCK_BEAUTIFULSHINE_DESC"] = "Chico, ven aquí. Tengo un pequeño trabajo paralelo para ti, ¿de acuerdo? No menciones lo que voy a decir a nadie. Unos amigos míos necesitan algo de oro, pero nuestras reservas están bajas. Mantener a estas personas contentas es de nuestro interés, así que necesito tu ayuda. Consígueme 3 lingotes de oro y puedo darte un buen montón de tapas, no dólares, tapas. Incluso te daré algunas de esas cosas de energía que no usamos, ¿de acuerdo? Esto puede llevarte un tiempo, así que los mantendré a raya mientras buscas. Haz esto y daré una buena palabra por ti con ellos, ¿de acuerdo?"
lang["#MISSION_SALTROCK_BEAUTIFULSHINE_HINT"] = "Consigue un Lingote de Oro. Se pueden encontrar en Cajas Fuertes raramente. Esto puede llevar algún tiempo para completarse."
lang["#MISSION_SALTROCK_BEAUTIFULSHINE_COMPLETE"] = "Increíble. Aquí está tu parte. Y uh, ellos ya saben tu nombre. Mantente a salvo, chico."

lang["#MISSION_SALTROCK_OLDEQUIPMENT"] = "Equipo Viejo, Parte 1"
lang["#MISSION_SALTROCK_OLDEQUIPMENT_DESC"] = "$playername, tengo un trabajo especial para ti. Vivir aquí abajo es agradable, pero a veces es difícil. He estado tratando de localizar equipo que nos pueda dar una idea de lo que estamos excavando, pero han sido callejones sin salida durante años, hasta hace poco. Conseguí algunos registros de transporte antiguos de algunos sensores remotos de uno de esos tipos en Salem, y puede que haya encontrado oro. Resulta que había un envío de ellos siendo transportado a la Cantera en Salt Wells, pero nunca llegó allí. No puedo enviar a ninguno de mis chicos normales porque la RNC los verá y los masacrará, pero tú pareces que puedes cuidarte solo. Encuentra la caja y tráela de vuelta."
lang["#MISSION_SALTROCK_OLDEQUIPMENT_HINT"] = "Encuentra el Envío de Sensores de Antes de la Guerra en algún lugar de Salt Wells. Estaba destinado a llegar a la cantera, pero nunca lo hizo."
lang["#MISSION_SALTROCK_OLDEQUIPMENT_COMPLETE"] = "Buena tecnología. Veré si puedo ponerla en funcionamiento. Toma una recompensa, de nuestra parte."
lang["#MISSION_SALTROCK_OLDEQUIPMENT_ITEMNAME"] = "Equipo de Antes de la Guerra"

lang["#MISSION_SALTROCK_OLDEQUIPMENTPART2"] = "Equipo Viejo, Parte 2"
lang["#MISSION_SALTROCK_OLDEQUIPMENTPART2_DESC"] = "Buen trabajo encontrando ese envío, un montón del equipo que necesitamos, pero ahora es el momento de algunas de las piezas más especializadas. Una de las cosas principales aquí le falta un componente central que no estaba incluido en ese envío. Es algún tipo de sensor central o algo así. Dudo que encontremos uno debido a, uh, todo lo que pasó, pero podemos hacer que funcione. Hablé con Gadget y dijo que podemos arrancarlo de un dispositivo existente, así que tengo un plan. Había otro sitio de excavación en algún lugar de esta cordillera, necesito que lo encuentres y veas si puedes recuperar algo de equipo de allí, específicamente cualquier equipo sensor viejo que puedan tener para que Gadget pueda desarmarlo. Lo único que sé sobre su ubicación es que tenía un camino sinuoso que llevaba hasta él, pero eso es todo. Buena suerte chico."
lang["#MISSION_SALTROCK_OLDEQUIPMENTPART2_HINT"] = "Localiza el área minera de antes de la guerra en Yolla Bolly. La única pista que tienes es que tiene un camino sinuoso que lleva hasta ella. Localiza el equipo y tráelo de vuelta."
lang["#MISSION_SALTROCK_OLDEQUIPMENTPART2_COMPLETE"] = "¡Esto parece algo que puede funcionar! Se lo pasaré a Gadget, hermoso chico."
lang["#MISSION_SALTROCK_OLDEQUIPMENTPART2_ITEMNAME"] = "Sensor Viejo"

lang["#MISSION_SALTROCK_OLDEQUIPMENTPART3"] = "Equipo Viejo, Parte 3"
lang["#MISSION_SALTROCK_OLDEQUIPMENTPART3_DESC"] = "Este es el trato. Estamos configurando un sistema con todos los Maestros de Herramientas con Gadget a la cabeza, y han hecho una lista de cosas que necesitan ahora mismo para poner todo el equipo en funcionamiento. Me tocó mi parte de la lista, lo que significa que es tu parte de la lista. Soy demasiado mayor para estar saqueando, y también, con lo que esos malditos hombres de la frontera me hicieron cuando me encontraron, no quiero volver a salir allí. Consigue las cosas, y luego veremos los frutos de nuestro trabajo."
lang["#MISSION_SALTROCK_OLDEQUIPMENTPART3_HINT"] = "Recoge varios objetos. Los Motores de Gasolina se pueden obtener de coches desguazados o mediante trueque. Los otros se pueden obtener saqueando o mediante trueque."
lang["#MISSION_SALTROCK_OLDEQUIPMENTPART3_COMPLETE"] = "Lo enviaré, veamos si ese es el final de todo este ir y venir."

lang["#MISSION_SALTROCK_OLDEQUIPMENTPART4"] = "Equipo Viejo, Parte 4"
lang["#MISSION_SALTROCK_OLDEQUIPMENTPART4_DESC"] = "Bueno, una cosa más. Pudieron poner en funcionamiento todos los sensores y esas cosas, pero necesitan algún tipo de computadora especial para ello, ¿algún tipo de Sistema Operativo específico o algo así? Los Maestros de Herramientas son los que saben todo esto, pero necesitan una computadora especial. Hay una vieja instalación de reparación de electrónica Apricot al norte de aquí, en un lugar llamado Las Tierras de Ceniza por los lugareños hoy en día. Debería ser un edificio de tres pisos más o menos, pero entra allí, agarra la Terminal y sal de allí. Lo único que escucho sobre ese infierno es que es una zona de guerra constante, así que mantén la cabeza baja, encuentra la fábrica, consigue la computadora y vuelve aquí con la misma cantidad de agujeros con los que te fuiste, ¿de acuerdo chico?"
lang["#MISSION_SALTROCK_OLDEQUIPMENTPART4_HINT"] = "Localiza la instalación de reparación de electrónica Apricot y obtén la terminal. Es un edificio de 3 pisos en algún lugar de las Tierras de Ceniza."
lang["#MISSION_SALTROCK_OLDEQUIPMENTPART4_COMPLETE"] = "¡Sí! ¡Absolutamente perfecto! ¡Has cambiado todo $playername, jodidamente hermoso!"
lang["#MISSION_SALTROCK_OLDEQUIPMENTPART4_ITEMNAME"] = "Terminal de Computadora Apricot"

-- Repetibles disponibles después de la Parte 4 de Equipo Viejo

lang["#MISSION_FIGHT_THE_POWER"] = "Lucha Contra el Poder"
lang["#MISSION_FIGHT_THE_POWER_DESC"] = "$playername, tengo un trabajo para ti. La RNC se ha estado poniendo un poco engreída. Así que creo que sería una buena idea mantenerlos distraídos eliminando a algunos de sus oficiales en el área de Salt Wells."
lang["#MISSION_FIGHT_THE_POWER_HINT"] = "Mata a 1 Capitán de la RNC, 2 Oficiales de Control de Disturbios de la RNC y 5 Tenientes de la RNC en la región de Salt Wells."
lang["#MISSION_FIGHT_THE_POWER_COMPLETE"] = "Jaja, buen trabajo chico. Esas perras burocráticas se estarán tropezando tratando de reemplazar a esos tipos."

lang["#MISSION_SALTROCK_HOLDING_THE_PICKET_LINE"] = "Manteniendo la Línea (de Piquete)"
lang["#MISSION_SALTROCK_HOLDING_THE_PICKET_LINE_DESC"] = "Hiciste un buen trabajo con esos Supervivientes del Valle, pero esos Rangers los están ayudando a levantarse. Parece que algunas personas nunca aprenden a no meter la nariz en los asuntos de los demás. Derriba a esos Rangers del Desierto un par de escalones para mí, ¿quieres?"
lang["#MISSION_SALTROCK_HOLDING_THE_PICKET_LINE_HINT"] = "Mata a 15 Rangers del Desierto."
lang["#MISSION_SALTROCK_HOLDING_THE_PICKET_LINE_COMPLETE"] = "Maravilloso, maravilloso. Algunas personas simplemente no lo entienden."

RELOADSCHEMA = true